{
  "shots": [
    {
      "shot_id": "SH11",
      "priority": "P0",
      "intent": "承接美咲的承诺，让樱子在没有躲开的亲近中主动询问健一的安危，呈现她对健一的信任与仍未消散的恐惧。",
      "duration_sec": 5,
      "shot_type": "双人中近景",
      "movement": "固定机位",
      "framing_focus": "首帧为行驶中的列车车厢内稳定双人中近景：佐藤樱子正脸偏三分位于画面中心偏右，抬眼看向佐藤美咲，嘴部清楚可见，一只手攥住SAKURA_SCHOOL_UNIFORM_EP22深色裙摆；佐藤美咲三分脸位于画面左侧，右手仍轻放在樱子校服袖口上，嘴唇闭合。",
      "action_intent": "本镜头只承担樱子一句提问：她没有避开美咲落在袖口上的手，身体微微靠近，攥紧校服裙摆，低声问健一叔叔会不会好；美咲全程闭嘴倾听。",
      "emotion_intent": "樱子的稚嫩不安与刚建立的信任同时可见，美咲以沉默的眼神接住她的担心。",
      "scene_id": "EP22_TRAIN_CARRIAGE_MOVING",
      "scene_name": "行驶中的列车车厢",
      "dialogue": [
        {
          "speaker": "佐藤樱子",
          "text": "姨妈，健一叔叔……他会好吗？",
          "purpose": "让樱子在靠近美咲后主动关心健一，确认她对健一产生信任，同时保留对真相和未来的恐惧。",
          "source": "onscreen",
          "listener": "佐藤美咲"
        }
      ],
      "narration": [],
      "subtitle": [
        "姨妈，健一叔叔……他会好吗？"
      ],
      "positive_core": "首帧为行驶中的列车车厢内稳定双人中近景：佐藤樱子正脸偏三分位于画面中心偏右，抬眼看向佐藤美咲，嘴部清楚可见，一只手攥住SAKURA_SCHOOL_UNIFORM_EP22深色裙摆，佐藤美咲三分脸位于画面左侧，右手仍轻放在樱子校服袖口上，嘴唇闭合。车厢灯光低饱和，窗边有蓝紫与暖黄城市光影掠过；樱子只做极轻微靠近和手指收紧的动作，说完后仍看着美咲；美咲保持沉默、眼线接住樱子的抬眼，人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "first_frame_contract": {
        "location": "行驶中的列车车厢",
        "visual_center": "佐藤樱子抬眼看向美咲的脸与清楚可见的嘴部",
        "visible_characters": [
          "佐藤樱子",
          "佐藤美咲"
        ],
        "character_positions": {
          "佐藤樱子": "画面中心偏右，坐在美咲身旁，身体微微靠近美咲",
          "佐藤美咲": "画面左侧，三分脸朝向樱子，右手轻放在樱子校服袖口上"
        },
        "character_face_visibility": {
          "佐藤樱子": "脸部可见，正脸偏三分；可见五官、眼神和嘴部",
          "佐藤美咲": "脸部可见，三分脸；可见五官和眼神，嘴唇闭合"
        },
        "key_props": [
          "SAKURA_SCHOOL_UNIFORM_EP22"
        ],
        "speaking_state": "佐藤樱子是唯一画面内说话人；佐藤美咲沉默闭嘴；没有远端声音",
        "camera_motion_allowed": "固定机位"
      },
      "dialogue_blocking": {
        "active_speaker": "佐藤樱子",
        "first_speaker": "佐藤樱子",
        "speaker_visual_priority": "center_face",
        "silent_visible_characters": [
          "佐藤美咲"
        ],
        "lip_sync_policy": "single_active_speaker"
      },
      "i2v_contract": {
        "shot_task": "dialogue",
        "risk_level": "low",
        "risk_notes": "单一车厢地点、单一画面内说话人、无电话；动作只限樱子轻微靠近和攥紧裙摆，适合I2V稳定生成。",
        "prop_library": {
          "SAKURA_SCHOOL_UNIFORM_EP22": {
            "display_name": "樱子校服",
            "count": "1套",
            "size": "适配中学生身形，裙摆至膝部附近",
            "color": "深蓝上衣、白色衬衫、深色裙摆",
            "material": "棉混纺制服布料",
            "structure": "日常校服套装，衣着完整，裙摆自然平整",
            "front_description": "不适用，非照片道具",
            "back_description": "不适用，非照片道具",
            "canonical_motion_policy": "随樱子坐姿和手部按压产生轻微褶皱；不脱离角色身体"
          }
        },
        "prop_contract": [
          {
            "prop_id": "SAKURA_SCHOOL_UNIFORM_EP22",
            "position": "首帧穿在佐藤樱子身上，深色裙摆位于画面下半部，樱子一只手攥住裙摆",
            "first_frame_visible": true,
            "motion_policy": "随樱子手指轻微收紧产生小幅褶皱，数量固定为1套，始终保持穿着状态",
            "controlled_by": "佐藤樱子",
            "current_visible_side": "none",
            "orientation_to_camera": "不适用，非照片道具",
            "quantity_policy": "数量固定为1套，画面只呈现这一套校服",
            "flip_policy": "不适用，非照片道具"
          }
        ],
        "phone_contract": {
          "holder": "none",
          "screen_orientation": "none",
          "screen_content_visible": false
        }
      },
      "source_basis": "樱子的手心微微出汗；她没抽开，反而靠得近；姨妈，健一叔叔……他会好吗？"
    }
  ],
  "qa_report": [
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "仅生成SH11；单一地点为行驶中的列车车厢；单一主动说话人为佐藤樱子；佐藤美咲可见但沉默无口型；首帧两人脸部均可见；关键道具SAKURA_SCHOOL_UNIFORM_EP22沿用目录设定；无电话对白。"
    }
  ]
}
